const s={id:"blog-ranger-elf-elara-nightwhisper",variant:"dnd5e",name:"Elara Nightwhisper",playerName:"",race:"elf",subrace:"wood-elf",className:"ranger",subclass:"hunter",level:5,background:"outlander",alignment:"cg",experiencePoints:6500,abilityScores:{str:10,dex:15,con:14,int:10,wis:14,cha:8},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:2,con:0,int:0,wis:1,cha:0},skillProficiencies:["perception","stealth","nature","athletics","survival"],skillExpertise:[],savingThrowProficiencies:["str","dex"],languages:["Common","Elvish","Sylvan"],proficienciesOther:["light armor","medium armor","shields","simple weapons","martial weapons"],weapons:[{name:"Longbow",attackBonus:7,damage:"1d8+3"},{name:"Shortsword",attackBonus:7,damage:"1d6+3"},{name:"Shortsword",attackBonus:7,damage:"1d6+3"}],armor:"Studded Leather",shield:!1,equipment:["Studded Leather Armor","Quiver of 20 arrows","Dungeoneer's Pack","Hunting trap","Staff","Trophy from a dire wolf","Traveler's clothes","Rope (50 ft)"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I watch over my friends as if they were a litter of newborn pups. I feel far more comfortable around animals than people.",ideals:"Nature. The natural world is more important than all the constructs of civilization.",bonds:"An injury to the unspoiled wilderness of my home is an injury to me.",flaws:"I am slow to trust members of other races, towns, and societies.",featuresTraits:["Darkvision","Keen Senses","Fey Ancestry","Trance","Mask of the Wild","Favored Enemy","Natural Explorer","Fighting Style: Archery","Spellcasting","Ranger Archetype: Hunter","Hunter's Prey: Colossus Slayer","Primeval Awareness","Extra Attack"],backstory:"Born one hundred and twenty-seven years ago beneath the silver canopy of the Whispering Woods, Elara was raised among a secluded community of wood elves who served as wardens of the forest. From childhood she learned to read animal tracks, navigate by starlight, and move through the undergrowth without disturbing a single leaf. When a band of gnoll marauders burned the eastern grove and scattered her kin, Elara took up the longbow and swore an oath to hunt those who threaten the wilds. She has spent decades roaming the frontier, guided by the wind and the call of the wolf, offering her skills to any settlement threatened by monstrous incursions.",age:"127",height:`5'10"`,weight:"130 lbs",eyes:"Green",hair:"Silver",skin:"Copper",allies:"Circle of the Silverleaf — a loose network of elven rangers",treasure:"A carved wooden amulet depicting a wolf",spellcastingClass:"ranger",spellcastingAbility:"wis",cantrips:[],spellsKnown:["Hunter's Mark","Cure Wounds","Goodberry","Pass without Trace"],spellsPrepared:[],hitDie:10,maxHp:44,currentHp:44,tempHp:0,speed:35,sessionNotes:"",classes:[]},n={id:"blog-barbarian-halforc-grokk-ironfang",variant:"dnd5e",name:"Grokk Ironfang",playerName:"",race:"half-orc",subrace:"",className:"barbarian",subclass:"berserker",level:5,background:"soldier",alignment:"cn",experiencePoints:6500,abilityScores:{str:15,dex:13,con:14,int:8,wis:12,cha:10},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:2,dex:0,con:1,int:0,wis:0,cha:0},skillProficiencies:["athletics","intimidation","perception","survival"],skillExpertise:[],savingThrowProficiencies:["str","con"],languages:["Common","Orc"],proficienciesOther:["light armor","medium armor","shields","simple weapons","martial weapons"],weapons:[{name:"Greataxe",attackBonus:6,damage:"1d12+3"},{name:"Handaxe",attackBonus:6,damage:"1d6+3"},{name:"Handaxe",attackBonus:6,damage:"1d6+3"}],armor:"",shield:!1,equipment:["Greataxe","2 Handaxes","Explorer's Pack","4 Javelins","Traveler's clothes"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I can stare down a hell hound without flinching. I enjoy being strong and like breaking things.",ideals:"Might. In life as in war, the stronger force wins.",bonds:"I will never forget the mercenary company that took me in when no one else would.",flaws:"My rage is difficult to control, and I have hurt people I care about when the fury takes me.",featuresTraits:["Darkvision","Menacing","Relentless Endurance","Savage Attacks","Rage","Unarmored Defense","Reckless Attack","Danger Sense","Primal Path: Path of the Berserker","Extra Attack","Fast Movement","Frenzy"],backstory:"Grokk grew up on the fringes of orcish war-camps, never fully accepted by either humans or orcs until a mercenary captain named Dara Voss recognised his raw talent and gave him a place in her Iron Fang Company. He served faithfully for six years, but during the Siege of Ashford his rage spiralled beyond control and he turned on his own comrades, leaving three wounded before he could be restrained. Expelled in disgrace, Grokk now roams the borderlands alone, seeking battles worthy of his fury and a way to master the beast that lives inside him.",age:"24",height:`6'4"`,weight:"250 lbs",eyes:"Red",hair:"Black",skin:"Grey-green",allies:"Former comrades of the Iron Fang Company",treasure:"A chipped tusk pendant from his orcish father",spellcastingClass:"",spellcastingAbility:"",cantrips:[],spellsKnown:[],spellsPrepared:[],hitDie:12,maxHp:50,currentHp:50,tempHp:0,speed:30,sessionNotes:"",classes:[]},t={id:"blog-bard-halfelf-lyra-silvertongue",variant:"dnd5e",name:"Lyra Silvertongue",playerName:"",race:"half-elf",subrace:"",className:"bard",subclass:"college-of-lore",level:5,background:"entertainer",alignment:"cg",experiencePoints:6500,abilityScores:{str:8,dex:14,con:14,int:10,wis:10,cha:15},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:1,con:0,int:0,wis:1,cha:2},skillProficiencies:["persuasion","performance","deception","acrobatics","insight","arcana","history"],skillExpertise:[],savingThrowProficiencies:["dex","cha"],languages:["Common","Elvish","Sylvan"],proficienciesOther:["light armor","simple weapons","hand crossbow","longsword","rapier","shortsword"],weapons:[{name:"Rapier",attackBonus:5,damage:"1d8+2"},{name:"Dagger",attackBonus:5,damage:"1d4+2"}],armor:"Studded Leather",shield:!1,equipment:["Rapier","Diplomat's Pack","Lute","Dagger","Studded Leather Armor"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I know a story relevant to almost every situation. Nobody stays angry at me or around me for long, since I can defuse any amount of tension.",ideals:"Beauty. When I perform, I make the world better than it was.",bonds:"I owe my mentor a great debt for forging me into the person I am today.",flaws:"I have trouble keeping my true feelings hidden. My sharp tongue lands me in trouble.",featuresTraits:["Darkvision","Fey Ancestry","Skill Versatility","Spellcasting","Bardic Inspiration","Jack of All Trades","Song of Rest","Bard College: College of Lore","Expertise","Font of Inspiration","Cutting Words","Bonus Proficiencies"],backstory:"Lyra was born to a human merchant and an elven diplomat in the bustling port city of Whitereach, inheriting her mother's pointed ears and her father's restless ambition. She apprenticed under a legendary troubadour named Orso the Golden, learning not only music and stagecraft but the subtle art of weaving enchantments into words. When Orso disappeared under mysterious circumstances, Lyra took to the open road, performing in taverns and noble courts alike while secretly searching for clues to her mentor's fate. Her wit is as sharp as any blade, and she has talked her way out of more dungeons than most adventurers have walked into.",age:"28",height:`5'7"`,weight:"125 lbs",eyes:"Violet",hair:"Auburn",skin:"Fair",allies:"The Whitereach Players — a traveling troupe of performers",treasure:"An ornate silver lute pick given by her mentor Orso",spellcastingClass:"bard",spellcastingAbility:"cha",cantrips:["Vicious Mockery","Minor Illusion"],spellsKnown:["Healing Word","Faerie Fire","Thunderwave","Charm Person","Hold Person","Invisibility","Dispel Magic","Cure Wounds"],spellsPrepared:[],hitDie:8,maxHp:38,currentHp:38,tempHp:0,speed:30,sessionNotes:"",classes:[]},r={id:"blog-cleric-dwarf-thordin-stoneheart",variant:"dnd5e",name:"Thordin Stoneheart",playerName:"",race:"dwarf",subrace:"hill-dwarf",className:"cleric",subclass:"life",level:5,background:"acolyte",alignment:"lg",experiencePoints:6500,abilityScores:{str:14,dex:10,con:14,int:8,wis:15,cha:10},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:0,con:2,int:0,wis:1,cha:0},skillProficiencies:["insight","religion","medicine","history"],skillExpertise:[],savingThrowProficiencies:["wis","cha"],languages:["Common","Dwarvish","Celestial"],proficienciesOther:["light armor","medium armor","heavy armor","shields","simple weapons","warhammer","battleaxe","handaxe","light hammer"],weapons:[{name:"Warhammer",attackBonus:5,damage:"1d8+2"},{name:"Light Crossbow",attackBonus:3,damage:"1d8"}],armor:"Chain Mail",shield:!0,equipment:["Chain Mail","Shield","Warhammer","Light Crossbow","20 bolts","Priest's Pack","Holy symbol","Prayer book"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I see omens in every event and action. The gods try to speak to us, we just need to listen. I quote sacred texts and proverbs in almost every situation.",ideals:"Faith. I trust that my deity will guide my actions. I have faith that if I work hard, things will go well.",bonds:"I would die to recover an ancient relic of my faith that was lost long ago.",flaws:"I judge others harshly, and myself even more severely. I put too much trust in those who wield power within my temple.",featuresTraits:["Darkvision","Dwarven Resilience","Dwarven Combat Training","Stonecunning","Dwarven Toughness","Spellcasting","Divine Domain: Life","Bonus Proficiency","Disciple of Life","Channel Divinity","Channel Divinity: Turn Undead","Destroy Undead"],backstory:"Thordin was born deep within the mountain halls of Ironhold, where the ringing of hammers on anvils served as a hymn to the forge god Moradin. He trained for decades as a temple smith-priest, learning to channel divine power through prayer and the rhythmic striking of metal. When a plague of undeath swept through the lower mines, Thordin took up his warhammer and holy symbol and descended alone to purge the corruption, emerging three days later battered but victorious. Now he travels the surface world, believing Moradin has called him to bring healing and light wherever darkness festers.",age:"185",height:`4'4"`,weight:"175 lbs",eyes:"Brown",hair:"Grey",skin:"Tan",allies:"The Temple of the Eternal Forge in Ironhold",treasure:"A silver holy symbol set with a garnet",spellcastingClass:"cleric",spellcastingAbility:"wis",cantrips:["Sacred Flame","Guidance","Light"],spellsKnown:[],spellsPrepared:["Cure Wounds","Healing Word","Bless","Shield of Faith","Aid","Lesser Restoration","Spirit Guardians","Revivify"],hitDie:8,maxHp:48,currentHp:48,tempHp:0,speed:25,sessionNotes:"",classes:[]},i={id:"blog-druid-human-rowan-ashwood",variant:"dnd5e",name:"Rowan Ashwood",playerName:"",race:"human",subrace:"",className:"druid",subclass:"circle-of-the-land",level:5,background:"hermit",alignment:"tn",experiencePoints:6500,abilityScores:{str:10,dex:14,con:14,int:12,wis:15,cha:8},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:1,dex:1,con:1,int:1,wis:1,cha:1},skillProficiencies:["nature","survival","medicine","religion"],skillExpertise:[],savingThrowProficiencies:["int","wis"],languages:["Common","Druidic","Elvish","Sylvan"],proficienciesOther:["light armor","medium armor","shields","club","dagger","dart","javelin","mace","quarterstaff","scimitar","sickle","sling","spear","herbalism kit"],weapons:[{name:"Scimitar",attackBonus:5,damage:"1d6+2"},{name:"Quarterstaff",attackBonus:3,damage:"1d6"}],armor:"Leather",shield:!0,equipment:["Leather Armor","Wooden Shield","Scimitar","Explorer's Pack","Druidic focus (yew wand)","Herbalism kit","Scroll case of notes"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I feel tremendous empathy for all who suffer. I connect everything that happens to me to a grand, cosmic plan.",ideals:"Greater Good. My gifts are meant to be shared with all, not used for my own benefit.",bonds:"I entered seclusion because I discovered a truth about nature that no one else should know, and I must protect it.",flaws:"I often get lost in my own thoughts and contemplation, becoming oblivious to my surroundings.",featuresTraits:["Druidic","Spellcasting","Wild Shape","Druid Circle: Circle of the Land","Bonus Cantrip","Natural Recovery"],backstory:"Rowan once lived as a simple woodcutter in a farming village on the edge of the Thornweald, until the night a dying treant collapsed at the edge of his field and whispered the secret language of the forest into his ear. Overwhelmed by the sudden flood of primal awareness, he abandoned his home and retreated deep into the wilderness to study the druidic arts under the guidance of the ancient spirits that dwell in root and stone. For seven years he lived alone, eating only what the land offered and learning to shape-shift into the creatures he shared the forest with. He emerged changed, quiet and watchful, dedicated to maintaining the delicate balance between civilization and the wild.",age:"34",height:`5'11"`,weight:"165 lbs",eyes:"Hazel",hair:"Brown",skin:"Weathered tan",allies:"The Thornweald Circle — a druidic conclave",treasure:"A journal filled with observations of rare plants and animals",spellcastingClass:"druid",spellcastingAbility:"wis",cantrips:["Druidcraft","Produce Flame","Shillelagh"],spellsKnown:[],spellsPrepared:["Cure Wounds","Faerie Fire","Thunderwave","Goodberry","Pass without Trace","Hold Person","Lesser Restoration","Dispel Magic"],hitDie:8,maxHp:38,currentHp:38,tempHp:0,speed:30,sessionNotes:"",classes:[]},o={id:"blog-fighter-dwarf-bera-battlehammer",variant:"dnd5e",name:"Bera Battlehammer",playerName:"",race:"dwarf",subrace:"mountain-dwarf",className:"fighter",subclass:"champion",level:5,background:"soldier",alignment:"ln",experiencePoints:6500,abilityScores:{str:15,dex:13,con:14,int:10,wis:12,cha:8},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:2,dex:0,con:2,int:0,wis:0,cha:0},skillProficiencies:["athletics","intimidation","perception","acrobatics"],skillExpertise:[],savingThrowProficiencies:["str","con"],languages:["Common","Dwarvish"],proficienciesOther:["all armor","shields","simple weapons","martial weapons","smith's tools"],weapons:[{name:"Battleaxe",attackBonus:6,damage:"1d8+3"},{name:"Handaxe",attackBonus:6,damage:"1d6+3"},{name:"Handaxe",attackBonus:6,damage:"1d6+3"}],armor:"Chain Mail",shield:!0,equipment:["Chain Mail","Shield","Battleaxe","2 Handaxes","Dungeoneer's Pack","Rank insignia","Trophy from a fallen foe"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I face problems head-on. A simple, direct solution is the best path to success. I can stare down a hell hound without flinching.",ideals:"Responsibility. I do what I must and obey just authority.",bonds:"My honour is my life. I would rather die than break my oath to the shield corps.",flaws:"I made a terrible mistake in battle that cost many lives, and I would do anything to keep that secret.",featuresTraits:["Darkvision","Dwarven Resilience","Dwarven Combat Training","Dwarven Armor Training","Stonecunning","Fighting Style: Defense","Second Wind","Action Surge","Martial Archetype: Champion","Improved Critical","Extra Attack"],backstory:"Bera was forged in the crucible of the Stoneguard Shield Corps, the elite dwarven heavy infantry that defends the mountain kingdom of Karak Dorn from the endless tide of goblinoids and worse things that boil up from the depths. She earned her family name Battlehammer not by birth but by deed, holding a collapsed tunnel entrance alone for twelve hours against a swarm of troglodytes until reinforcements arrived. Promoted to sergeant and decorated with the Iron Star, she eventually left the corps when a dispute with a corrupt commander made her position untenable. Now she hires her shield and axe to worthy causes, carrying the discipline and unyielding resolve of the dwarven military wherever she goes.",age:"92",height:`4'5"`,weight:"170 lbs",eyes:"Steel blue",hair:"Copper",skin:"Bronze",allies:"The Stoneguard Shield Corps of Karak Dorn",treasure:"An Iron Star medal and her sergeant's rank pin",spellcastingClass:"",spellcastingAbility:"",cantrips:[],spellsKnown:[],spellsPrepared:[],hitDie:10,maxHp:49,currentHp:49,tempHp:0,speed:25,sessionNotes:"",classes:[]},l={id:"blog-monk-elf-kael-windwalker",variant:"dnd5e",name:"Kael Windwalker",playerName:"",race:"elf",subrace:"wood-elf",className:"monk",subclass:"way-of-the-open-hand",level:5,background:"hermit",alignment:"ln",experiencePoints:6500,abilityScores:{str:10,dex:15,con:14,int:8,wis:14,cha:10},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:2,con:0,int:0,wis:1,cha:0},skillProficiencies:["acrobatics","stealth","medicine","religion"],skillExpertise:[],savingThrowProficiencies:["str","dex"],languages:["Common","Elvish","Dwarvish"],proficienciesOther:["simple weapons","shortsword"],weapons:[{name:"Shortsword",attackBonus:6,damage:"1d6+3"},{name:"Unarmed Strike",attackBonus:6,damage:"1d6+3"}],armor:"",shield:!1,equipment:["Shortsword","Explorer's Pack","10 darts","Prayer beads","Herbalism kit","Common clothes"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I am utterly serene, even in the face of disaster. I feel tremendous empathy for all who suffer.",ideals:"Self-Knowledge. If you know yourself, there is nothing left to know.",bonds:"I entered seclusion to master the way of the open hand, and I must prove worthy of my master's teachings.",flaws:"I am dogmatic in my thoughts and philosophy, and I look down on those who lack discipline.",featuresTraits:["Darkvision","Keen Senses","Fey Ancestry","Trance","Mask of the Wild","Martial Arts","Ki","Unarmored Defense","Unarmored Movement","Monastic Tradition: Way of the Open Hand","Open Hand Technique","Deflect Missiles","Slow Fall","Stunning Strike","Extra Attack"],backstory:"Kael was born among the wood elves of the Verdant Vale but showed little interest in the bow or the hunt, drawn instead to the travelling monks who occasionally passed through the forest on pilgrimage. At the age of forty he left his family and climbed to the Storm Peak Monastery, where he spent three decades learning to channel ki through breath and movement under the tutelage of the ancient master Shien. When a vision during deep meditation revealed a growing darkness spreading across the lowlands, Master Shien sent Kael down from the mountain to confront it, armed with nothing but his training and an unshakeable calm.",age:"72",height:`5'9"`,weight:"145 lbs",eyes:"Amber",hair:"Dark brown",skin:"Olive",allies:"The Storm Peak Monastery and Master Shien",treasure:"A set of prayer beads carved from storm-struck oak",spellcastingClass:"",spellcastingAbility:"",cantrips:[],spellsKnown:[],spellsPrepared:[],hitDie:8,maxHp:38,currentHp:38,tempHp:0,speed:45,sessionNotes:"",classes:[]},h={id:"blog-paladin-dragonborn-varek-brightscale",variant:"dnd5e",name:"Varek Brightscale",playerName:"",race:"dragonborn",subrace:"",className:"paladin",subclass:"oath-of-devotion",level:5,background:"noble",alignment:"lg",experiencePoints:6500,abilityScores:{str:15,dex:10,con:14,int:8,wis:12,cha:13},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:2,dex:0,con:0,int:0,wis:0,cha:1},skillProficiencies:["athletics","persuasion","history","religion"],skillExpertise:[],savingThrowProficiencies:["wis","cha"],languages:["Common","Draconic","Celestial"],proficienciesOther:["all armor","shields","simple weapons","martial weapons"],weapons:[{name:"Longsword",attackBonus:6,damage:"1d8+3"},{name:"Javelin",attackBonus:6,damage:"1d6+3"}],armor:"Chain Mail",shield:!0,equipment:["Chain Mail","Shield","Longsword","5 Javelins","Priest's Pack","Holy symbol","Signet ring","Scroll of pedigree","Fine clothes"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I take great pains to always look my best and follow the latest fashions. My favor, once lost, is lost forever.",ideals:"Responsibility. It is my duty to respect the authority of those above me, just as those below me must respect mine.",bonds:"I swore an oath before the golden altar of Bahamut that I would bring justice to the lawless frontier.",flaws:"I secretly believe that everyone is beneath me, and I have a hard time hiding that conviction.",featuresTraits:["Draconic Ancestry","Breath Weapon","Damage Resistance","Divine Sense","Lay on Hands","Fighting Style: Defense","Spellcasting","Divine Smite","Divine Health","Sacred Oath: Oath of Devotion","Channel Divinity: Sacred Weapon","Channel Divinity: Turn the Unholy","Extra Attack"],backstory:"Varek was hatched into the Brightscale clan, a lineage of gold dragonborn nobles who have served the temple of Bahamut for seven generations. Raised on tales of draconic honor and divine duty, he trained from youth in sword and prayer, excelling at both. When a plague of undead began pouring from the crypts beneath the family estate, Varek knelt before the high altar and swore the Oath of Devotion, vowing to be a beacon of light against the encroaching darkness. Now he rides forth clad in gleaming mail, his golden scales catching the sun like a living sigil of hope.",age:"28",height:`6'6"`,weight:"280 lbs",eyes:"Gold",hair:"",skin:"Golden scales",allies:"The Temple of the Platinum Dragon",treasure:"A gold-chased holy symbol bearing the crest of Clan Brightscale",spellcastingClass:"paladin",spellcastingAbility:"cha",cantrips:[],spellsKnown:[],spellsPrepared:["Bless","Cure Wounds","Shield of Faith","Aid","Lesser Restoration"],hitDie:10,maxHp:44,currentHp:44,tempHp:0,speed:30,sessionNotes:"",classes:[]},d={id:"blog-rogue-halfling-pip-shadowfoot",variant:"dnd5e",name:"Pip Shadowfoot",playerName:"",race:"halfling",subrace:"lightfoot",className:"rogue",subclass:"thief",level:5,background:"criminal",alignment:"cn",experiencePoints:6500,abilityScores:{str:8,dex:15,con:14,int:12,wis:13,cha:10},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:2,con:0,int:0,wis:0,cha:1},skillProficiencies:["stealth","sleight of hand","deception","acrobatics","perception","investigation"],skillExpertise:["stealth","sleight of hand"],savingThrowProficiencies:["dex","int"],languages:["Common","Halfling","Thieves' Cant"],proficienciesOther:["light armor","simple weapons","hand crossbow","longsword","rapier","shortsword","thieves' tools"],weapons:[{name:"Shortsword",attackBonus:6,damage:"1d6+3"},{name:"Dagger",attackBonus:6,damage:"1d4+3"}],armor:"Leather",shield:!1,equipment:["Shortsword","Shortbow","20 Arrows","Leather Armor","2 Daggers","Thieves' tools","Burglar's Pack","Dark common clothes with hood","Crowbar"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I always have a plan for what to do when things go wrong. The best way to get me to do something is to tell me I can't do it.",ideals:"Freedom. Chains are meant to be broken, as are those who would forge them.",bonds:"I owe everything to a retired burglar who taught me the trade and kept me off the gallows.",flaws:"When I see something valuable, I can't think about anything other than how to steal it.",featuresTraits:["Lucky","Brave","Halfling Nimbleness","Naturally Stealthy","Expertise","Sneak Attack","Thieves' Cant","Cunning Action","Roguish Archetype: Thief","Fast Hands","Second-Story Work","Uncanny Dodge"],backstory:`Pip never knew his parents; he was raised by a rotating cast of pickpockets, fences, and con artists in the sprawling underbelly of Waterdeep's Dock Ward. By the age of ten he could lift a coinpurse from a moving carriage, and by fifteen he had earned the street name "Shadowfoot" for his uncanny ability to vanish into any crowd. A botched heist against a noble house forced him to flee the city, and now he drifts from town to town, taking whatever jobs pay well and keep him one step ahead of the bounty hunters on his trail. Despite his larcenous ways, Pip lives by a strict code: never steal from anyone who cannot afford the loss.`,age:"32",height:`3'1"`,weight:"38 lbs",eyes:"Brown",hair:"Sandy",skin:"Tan",allies:"The Dock Ward Runners — a loose gang of former street urchins",treasure:"A lucky copper coin with both sides showing heads",spellcastingClass:"",spellcastingAbility:"",cantrips:[],spellsKnown:[],spellsPrepared:[],hitDie:8,maxHp:38,currentHp:38,tempHp:0,speed:25,sessionNotes:"",classes:[]},c={id:"blog-sorcerer-tiefling-zara-hellfire",variant:"dnd5e",name:"Zara Hellfire",playerName:"",race:"tiefling",subrace:"",className:"sorcerer",subclass:"draconic-bloodline",level:5,background:"sage",alignment:"cn",experiencePoints:6500,abilityScores:{str:8,dex:14,con:14,int:10,wis:10,cha:15},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:0,con:0,int:1,wis:0,cha:2},skillProficiencies:["arcana","history","insight","persuasion"],skillExpertise:[],savingThrowProficiencies:["con","cha"],languages:["Common","Infernal","Draconic"],proficienciesOther:["dagger","dart","sling","quarterstaff","light crossbow"],weapons:[{name:"Dagger",attackBonus:5,damage:"1d4+2"},{name:"Light Crossbow",attackBonus:5,damage:"1d8+2"}],armor:"",shield:!1,equipment:["Light Crossbow","20 Bolts","Component pouch","Dungeoneer's Pack","2 Daggers","Bottle of ink","Quill","Small knife","Letter from a dead colleague"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I use polysyllabic words that convey the impression of great erudition. There is nothing I like more than a good mystery.",ideals:"Knowledge. The path to power and self-improvement is through knowledge.",bonds:"I have an ancient text that holds terrible secrets about the origin of my bloodline, and it must not fall into the wrong hands.",flaws:"I overlook obvious solutions in favor of complicated ones, and I speak without really thinking through my words.",featuresTraits:["Darkvision","Hellish Resistance","Infernal Legacy","Spellcasting","Sorcerous Origin: Draconic Bloodline","Dragon Ancestor","Draconic Resilience","Font of Magic","Metamagic"],backstory:"Zara spent her youth buried in the restricted archives of the Candlekeep library, enduring the suspicious glares that her crimson skin and curling horns inevitably drew from the scholars around her. One night, while translating a crumbling scroll about the fall of an ancient red dragon, the parchment burst into flame in her hands and she discovered she could shape the fire at will. The revelation that dragon blood ran through her infernal veins sent her on a journey to trace her lineage back to its source. She now travels the realm seeking lost draconic relics, her fingers perpetually stained with ink and occasionally wreathed in flame.",age:"26",height:`5'8"`,weight:"140 lbs",eyes:"Amber",hair:"Raven black",skin:"Crimson",allies:"A circle of rogue scholars expelled from Candlekeep",treasure:"A fragment of dragon scale embedded in a silver pendant",spellcastingClass:"sorcerer",spellcastingAbility:"cha",cantrips:["Fire Bolt","Ray of Frost","Prestidigitation","Light"],spellsKnown:["Burning Hands","Shield","Scorching Ray","Misty Step","Fireball","Counterspell"],spellsPrepared:[],hitDie:6,maxHp:32,currentHp:32,tempHp:0,speed:30,sessionNotes:"",classes:[]},g={id:"blog-warlock-elf-vex-nightpact",variant:"dnd5e",name:"Vex Nightpact",playerName:"",race:"elf",subrace:"dark-elf",className:"warlock",subclass:"the-fiend",level:5,background:"charlatan",alignment:"ne",experiencePoints:6500,abilityScores:{str:8,dex:14,con:14,int:10,wis:10,cha:15},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:2,con:0,int:0,wis:0,cha:1},skillProficiencies:["deception","sleight of hand","arcana","investigation"],skillExpertise:[],savingThrowProficiencies:["wis","cha"],languages:["Common","Elvish","Abyssal"],proficienciesOther:["light armor","simple weapons"],weapons:[{name:"Light Crossbow",attackBonus:6,damage:"1d8+3"},{name:"Dagger",attackBonus:6,damage:"1d4+3"}],armor:"Leather",shield:!1,equipment:["Light Crossbow","20 Bolts","Leather Armor","2 Daggers","Scholar's Pack","Arcane focus (crystal orb)","Fine clothes","Disguise kit","Tools of the con"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I lie about almost everything, even when there is no good reason to. Flattery is my preferred trick for getting what I want.",ideals:"Independence. I am a free spirit — no one tells me what to do.",bonds:"A powerful fiend holds the other end of my pact, and I dread the day it comes to collect what I truly owe.",flaws:"I can't resist swindling people who are more powerful than me, and I'm convinced I can talk my way out of any situation.",featuresTraits:["Superior Darkvision","Keen Senses","Fey Ancestry","Trance","Sunlight Sensitivity","Drow Magic","Drow Weapon Training","Otherworldly Patron: The Fiend","Pact Magic","Dark One's Blessing","Eldritch Invocations","Pact Boon"],backstory:"Vex was born into a minor drow noble house whose matron sold him to a rival family as a political hostage before his twentieth year. During a botched assassination attempt that left him bleeding in a lightless corridor, a voice from the Abyss offered him power in exchange for servitude, and Vex accepted without hesitation. He clawed his way to the surface world, trading the intrigues of the Underdark for the cons and swindles of human cities. Now he plays a dangerous double game, using his patron's gifts to amass wealth and influence while scheming to find a way to break the pact before the devil takes its due.",age:"142",height:`5'5"`,weight:"120 lbs",eyes:"Pale lavender",hair:"White",skin:"Obsidian",allies:"A network of fences and smugglers across the Sword Coast",treasure:"A black iron ring that grows warm when his patron watches",spellcastingClass:"warlock",spellcastingAbility:"cha",cantrips:["Eldritch Blast","Chill Touch","Minor Illusion"],spellsKnown:["Hex","Burning Hands","Hold Person","Misty Step","Fireball","Counterspell"],spellsPrepared:[],hitDie:8,maxHp:38,currentHp:38,tempHp:0,speed:30,sessionNotes:"",classes:[]},p={id:"blog-wizard-elf-aldric-spellweaver",variant:"dnd5e",name:"Aldric Spellweaver",playerName:"",race:"elf",subrace:"high-elf",className:"wizard",subclass:"school-of-evocation",level:5,background:"sage",alignment:"ln",experiencePoints:6500,abilityScores:{str:8,dex:14,con:14,int:15,wis:10,cha:10},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:2,con:0,int:1,wis:0,cha:0},skillProficiencies:["arcana","history","investigation","perception"],skillExpertise:[],savingThrowProficiencies:["int","wis"],languages:["Common","Elvish","Draconic","Celestial"],proficienciesOther:["dagger","dart","sling","quarterstaff","light crossbow"],weapons:[{name:"Quarterstaff",attackBonus:2,damage:"1d6-1"},{name:"Dagger",attackBonus:6,damage:"1d4+3"}],armor:"",shield:!1,equipment:["Quarterstaff","Component pouch","Scholar's Pack","Spellbook","Bottle of ink","Quill","Parchment (10 sheets)","Small knife","Letter from a dead colleague"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I am horribly, horribly awkward in social situations. There is nothing I like more than a good mystery.",ideals:"Logic. Emotions must not cloud our sense of what is right and true, or our logical thinking.",bonds:"I have been searching my whole life for the answer to a certain question about the nature of magical energy.",flaws:"I am easily distracted by the promise of information, and I speak without really thinking through my words.",featuresTraits:["Darkvision","Keen Senses","Fey Ancestry","Trance","Elf Weapon Training","Spellcasting","Arcane Recovery","Arcane Tradition: School of Evocation","Evocation Savant","Sculpt Spells"],backstory:"Aldric spent his first century of life within the alabaster walls of the Starspire Academy, a tower of high elven magi perched atop the Silverpeak Mountains. He distinguished himself as a prodigy of evocation, mastering the precise geometry of fireball detonations while his peers were still fumbling with cantrips. When a catastrophic experiment by a rival student collapsed an entire wing of the tower and destroyed irreplaceable texts, Aldric set out into the wider world to recover the lost knowledge. He travels with a leather satchel full of annotated spellbooks, methodically cataloguing every arcane phenomenon he encounters with the thoroughness of a scholar and the caution of a soldier.",age:"215",height:`5'11"`,weight:"145 lbs",eyes:"Ice blue",hair:"Platinum blonde",skin:"Pale",allies:"The faculty of Starspire Academy",treasure:"A crystalline lens that reveals invisible ink when held to the eye",spellcastingClass:"wizard",spellcastingAbility:"int",cantrips:["Fire Bolt","Mage Hand","Light","Prestidigitation"],spellsKnown:[],spellsPrepared:["Magic Missile","Shield","Mage Armor","Scorching Ray","Misty Step","Fireball","Counterspell","Fly"],hitDie:6,maxHp:32,currentHp:32,tempHp:0,speed:30,sessionNotes:"",classes:[]},u={id:"blog-wizard-gnome-fizzle-gearspark",variant:"dnd5e",name:"Fizzle Gearspark",playerName:"",race:"gnome",subrace:"rock-gnome",className:"wizard",subclass:"evocation",level:3,background:"sage",alignment:"cg",experiencePoints:900,abilityScores:{str:8,dex:14,con:14,int:15,wis:10,cha:10},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:0,con:1,int:2,wis:0,cha:0},skillProficiencies:["arcana","history","investigation","nature"],skillExpertise:[],savingThrowProficiencies:["int","wis"],languages:["Common","Gnomish","Draconic"],proficienciesOther:["dagger","dart","sling","quarterstaff","light crossbow"],weapons:[{name:"Quarterstaff",attackBonus:0,damage:"1d6-1"},{name:"Light Crossbow",attackBonus:4,damage:"1d8+2"}],armor:"",shield:!1,equipment:["Quarterstaff","Component pouch","Scholar's Pack","Spellbook","Tinker's tools","Bottle of ink","Quill"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I use polysyllabic words that convey the impression of great erudition. There is nothing I like more than a good mystery, especially one that involves an explosion.",ideals:"Knowledge. The path to power and self-improvement is through knowledge, and every spell mastered is a door unlocked.",bonds:"I have been searching my whole life for the answer to a riddle my grandfather posed before he vanished in a flash of blue fire.",flaws:"I am easily distracted by the promise of new arcane knowledge and tend to forget about everything else, including danger.",featuresTraits:["Darkvision","Gnome Cunning","Artificer's Lore","Tinker","Spellcasting","Arcane Recovery","Arcane Tradition: School of Evocation","Evocation Savant","Sculpt Spells"],backstory:"Fizzle grew up in a gnomish enclave nestled within the roots of the Ironbark Mountains, where he spent his youth dismantling clocks and rebuilding them to shoot sparks. When a travelling wizard demonstrated a fireball to the village elders, young Fizzle knew he had found his true calling. He enrolled at the Arcanum Athenaeum, a crumbling academy where tuition was paid in curiosity and singed furnishings. After accidentally setting the dean's office ablaze during his thesis defence on controlled detonation theory, Fizzle decided the open road might offer fewer disciplinary hearings and far more interesting targets.",age:"68",height:`3'4"`,weight:"40 lbs",eyes:"Amber",hair:"Wild copper",skin:"Tan",allies:"The Arcanum Athenaeum — alumni network of eccentric wizards",treasure:"A tiny clockwork sparrow that chirps when magic is near",spellcastingClass:"wizard",spellcastingAbility:"int",cantrips:["Fire Bolt","Mage Hand","Prestidigitation"],spellsKnown:[],spellsPrepared:["Magic Missile","Shield","Burning Hands","Scorching Ray","Misty Step","Web"],hitDie:6,maxHp:20,currentHp:20,tempHp:0,speed:25,sessionNotes:"",classes:[]},m={id:"blog-fighter-halfling-bram-thickfoot",variant:"dnd5e",name:"Bram Thickfoot",playerName:"",race:"halfling",subrace:"stout",className:"fighter",subclass:"champion",level:3,background:"folk hero",alignment:"ng",experiencePoints:900,abilityScores:{str:15,dex:13,con:14,int:10,wis:12,cha:8},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:2,con:1,int:0,wis:0,cha:0},skillProficiencies:["athletics","perception","animal handling","survival"],skillExpertise:[],savingThrowProficiencies:["str","con"],languages:["Common","Halfling"],proficienciesOther:["all armor","shields","simple weapons","martial weapons"],weapons:[{name:"Shortsword",attackBonus:4,damage:"1d6+2"},{name:"Shortbow",attackBonus:4,damage:"1d6+2"}],armor:"Chain Mail",shield:!0,equipment:["Chain Mail","Shield","Shortsword","Shortbow","20 arrows","Dungeoneer's Pack","Smith's tools","Iron pot","Common clothes"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"If someone is in trouble, I am always ready to lend help. I stand up for those who cannot stand up for themselves, no matter how big the bully.",ideals:"Sincerity. There is no good in pretending to be something I am not. A strong arm and a kind heart are all any village needs.",bonds:"I defended my village from a gnoll warband and the people there still sing songs about it. I will never let them down.",flaws:"I am convinced that no one could ever fool me the way I fooled the gnolls, which makes me dangerously overconfident.",featuresTraits:["Lucky","Brave","Halfling Nimbleness","Stout Resilience","Fighting Style: Defense","Second Wind","Action Surge","Martial Archetype: Champion","Improved Critical"],backstory:"Bram grew up on a modest turnip farm in the Shire of Greenhollow, content with the simple rhythms of planting and harvest. That peace shattered the night a gnoll war-party descended on the village, and Bram found himself the last one standing on the old stone bridge, armed with nothing but a shovel and sheer stubbornness. By dawn, six gnolls lay in the river and Bram had earned a new nickname and a limp that still aches in the rain. Now hailed as a folk hero, he has taken up proper arms and set out to make sure no other small village suffers the way Greenhollow nearly did.",age:"32",height:`3'1"`,weight:"42 lbs",eyes:"Brown",hair:"Curly auburn",skin:"Ruddy",allies:"The people of Greenhollow",treasure:"A battered old shovel head he keeps as a lucky charm",spellcastingClass:"",spellcastingAbility:"",cantrips:[],spellsKnown:[],spellsPrepared:[],hitDie:10,maxHp:28,currentHp:28,tempHp:0,speed:25,sessionNotes:"",classes:[]},f={id:"blog-ranger-gnome-thistle-mossheart",variant:"dnd5e",name:"Thistle Mossheart",playerName:"",race:"gnome",subrace:"forest-gnome",className:"ranger",subclass:"hunter",level:3,background:"outlander",alignment:"ng",experiencePoints:900,abilityScores:{str:10,dex:15,con:14,int:10,wis:14,cha:8},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:1,con:0,int:2,wis:0,cha:0},skillProficiencies:["nature","stealth","perception","athletics","survival"],skillExpertise:[],savingThrowProficiencies:["str","dex"],languages:["Common","Gnomish","Sylvan"],proficienciesOther:["light armor","medium armor","shields","simple weapons","martial weapons"],weapons:[{name:"Shortsword",attackBonus:5,damage:"1d6+3"},{name:"Shortbow",attackBonus:5,damage:"1d6+3"}],armor:"Leather",shield:!1,equipment:["Leather Armor","Shortsword","Shortbow","20 arrows","Explorer's Pack","Hunting trap","Staff","Traveler's clothes"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I place no stock in wealthy or well-mannered folk. Money and manners will not save you from a hungry owlbear. I feel more at home among the roots and ferns than in any tavern.",ideals:"Nature. The natural world must be preserved, one tiny footprint at a time. Even the smallest creatures deserve a champion.",bonds:"The Mosswood gave me shelter when no settlement would. I owe everything to the ancient trees and the creatures who dwell among them.",flaws:"I talk to animals so often I sometimes forget how to talk to people, and I can be blunt to the point of rudeness.",featuresTraits:["Darkvision","Gnome Cunning","Natural Illusionist","Speak with Small Beasts","Favored Enemy","Natural Explorer","Fighting Style: Archery","Spellcasting","Ranger Archetype: Hunter","Hunter's Prey: Horde Breaker"],backstory:"Thistle was abandoned as an infant at the edge of the Mosswood, where a family of badgers and a sympathetic dryad raised him among the ferns and toadstools. He learned to speak with squirrels before he could speak Common and could track a beetle across bare stone by the age of twelve. When loggers began felling the old-growth oaks at the forest's border, Thistle took up bow and blade to defend his homeland. Now he ranges far beyond the Mosswood, building alliances with druids and fellow wardens to create a living shield around the wild places that still remain.",age:"75",height:`3'2"`,weight:"37 lbs",eyes:"Bright green",hair:"Mossy brown",skin:"Bark-brown",allies:"The dryad Willowmere and her circle of forest spirits",treasure:"A tiny acorn pendant that glows faintly in moonlight",spellcastingClass:"ranger",spellcastingAbility:"wis",cantrips:[],spellsKnown:["Hunter's Mark","Cure Wounds","Goodberry"],spellsPrepared:[],hitDie:10,maxHp:28,currentHp:28,tempHp:0,speed:25,sessionNotes:"",classes:[]},w={id:"blog-cleric-elf-arael-dawnwhisper",variant:"dnd5e",name:"Arael Dawnwhisper",playerName:"",race:"elf",subrace:"high-elf",className:"cleric",subclass:"life",level:3,background:"acolyte",alignment:"lg",experiencePoints:900,abilityScores:{str:10,dex:14,con:13,int:10,wis:15,cha:10},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:2,con:0,int:1,wis:0,cha:0},skillProficiencies:["insight","religion","medicine","history"],skillExpertise:[],savingThrowProficiencies:["wis","cha"],languages:["Common","Elvish","Celestial"],proficienciesOther:["light armor","medium armor","heavy armor","shields","simple weapons"],weapons:[{name:"Mace",attackBonus:2,damage:"1d6"},{name:"Light Crossbow",attackBonus:5,damage:"1d8+3"}],armor:"Scale Mail",shield:!0,equipment:["Scale Mail","Shield","Mace","Light Crossbow","20 bolts","Priest's Pack","Holy symbol","Prayer book","Vestments","Incense"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I see omens in every event and action. The gods try to speak to us; we just need to listen. I quote sacred texts and proverbs in almost every situation.",ideals:"Charity. I always try to help those in need, no matter what the personal cost. The light of dawn belongs to everyone.",bonds:"I owe my life to the temple that took me in after my homeland was destroyed. I will do anything to protect it and its people.",flaws:"I put too much trust in those who wield power within my temple hierarchy and too little trust in my own judgement.",featuresTraits:["Darkvision","Keen Senses","Fey Ancestry","Trance","Elf Weapon Training","Spellcasting","Divine Domain: Life","Bonus Proficiency","Disciple of Life","Channel Divinity","Channel Divinity: Turn Undead"],backstory:"Arael was born in a shining elven city that fell to an undead plague before he reached his first century. Orphaned and half-starved, he was found by travelling priests of the Dawnfather and raised within their austere hilltop temple. Under their guidance he discovered a gift for channelling restorative magic, his hands glowing with warm golden light whenever he tended the sick. Now ordained as a full cleric, Arael has left the temple to carry healing to the wider world, driven by a quiet conviction that no community should suffer the same fate as his homeland.",age:"148",height:`5'9"`,weight:"135 lbs",eyes:"Gold",hair:"Platinum blonde",skin:"Pale ivory",allies:"The Order of the Dawnfather — a travelling priestly order",treasure:"A golden sunrise pendant, the last relic of his birth city",spellcastingClass:"cleric",spellcastingAbility:"wis",cantrips:["Sacred Flame","Guidance","Light","Mage Hand"],spellsKnown:[],spellsPrepared:["Cure Wounds","Healing Word","Bless","Shield of Faith","Aid"],hitDie:8,maxHp:21,currentHp:21,tempHp:0,speed:30,sessionNotes:"",classes:[]},b={id:"blog-rogue-elf-nyx-shadowcloak",variant:"dnd5e",name:"Nyx Shadowcloak",playerName:"",race:"elf",subrace:"drow",className:"rogue",subclass:"thief",level:3,background:"urchin",alignment:"cn",experiencePoints:900,abilityScores:{str:8,dex:15,con:14,int:12,wis:13,cha:10},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:2,con:0,int:0,wis:0,cha:1},skillProficiencies:["stealth","acrobatics","sleight of hand","perception","deception","investigation"],skillExpertise:["stealth","perception"],savingThrowProficiencies:["dex","int"],languages:["Common","Elvish","Undercommon"],proficienciesOther:["light armor","simple weapons","hand crossbow","longsword","rapier","shortsword","thieves' tools"],weapons:[{name:"Shortsword",attackBonus:5,damage:"1d6+3"},{name:"Hand Crossbow",attackBonus:5,damage:"1d6+3"}],armor:"Leather",shield:!1,equipment:["Shortsword","Hand Crossbow","20 bolts","Leather Armor","2 Daggers","Thieves' tools","Burglar's Pack","Small knife","Map of the city","Pet mouse","Token from parents","Common clothes"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I hide scraps of food and trinkets in my pockets. I ask a lot of questions because you never know when a throwaway detail might save your life.",ideals:"Freedom. Chains are meant to be broken, as are those who would forge them. Nobody tells me what to do.",bonds:"I owe a debt I can never repay to the street gang that sheltered me when I first crawled out of the Underdark.",flaws:"If there is a plan, I will forget it. If I do not forget it, I will ignore it. Improvisation is my only true strategy.",featuresTraits:["Superior Darkvision","Keen Senses","Fey Ancestry","Trance","Sunlight Sensitivity","Drow Magic","Drow Weapon Training","Expertise","Sneak Attack","Thieves' Cant","Cunning Action","Roguish Archetype: Thief","Fast Hands","Second-Story Work"],backstory:"Nyx was born in a minor drow noble house that collapsed under political intrigue before she could walk. Cast out to the surface as a liability, she spent her childhood on the rain-slicked streets of Duskport, picking pockets and dodging city guards. A local thieves' guild called the Cobalt Rats took her in, teaching her the finer points of locks, ledges, and leverage. When the guild's leader was betrayed and arrested, Nyx slipped through a window that no one else could fit through and vanished into the night, carrying nothing but her wits and a grudge against anyone who abuses power.",age:"82",height:`5'4"`,weight:"110 lbs",eyes:"Lavender",hair:"White",skin:"Obsidian",allies:"The Cobalt Rats — a scattered thieves' guild in Duskport",treasure:"A tarnished silver locket containing a faded portrait of her mother",spellcastingClass:"",spellcastingAbility:"",cantrips:[],spellsKnown:[],spellsPrepared:[],hitDie:8,maxHp:24,currentHp:24,tempHp:0,speed:30,sessionNotes:"",classes:[]},y={id:"blog-paladin-human-ser-roland-the-bold",variant:"dnd5e",name:"Ser Roland the Bold",playerName:"",race:"human",subrace:"",className:"paladin",subclass:"devotion",level:3,background:"noble",alignment:"lg",experiencePoints:900,abilityScores:{str:15,dex:10,con:14,int:8,wis:12,cha:13},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:1,dex:1,con:1,int:1,wis:1,cha:1},skillProficiencies:["athletics","persuasion","history","religion"],skillExpertise:[],savingThrowProficiencies:["wis","cha"],languages:["Common","Celestial","Dwarvish"],proficienciesOther:["all armor","shields","simple weapons","martial weapons"],weapons:[{name:"Longsword",attackBonus:5,damage:"1d8+3"},{name:"Javelin",attackBonus:5,damage:"1d6+3"}],armor:"Chain Mail",shield:!0,equipment:["Chain Mail","Shield","Longsword","5 Javelins","Priest's Pack","Holy symbol","Signet ring","Scroll of pedigree","Fine clothes"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"My eloquent flattery makes everyone I talk to feel like the most wonderful and important person in the world. Despite my noble birth, I do not place myself above other folk.",ideals:"Honour. If I dishonour myself, I dishonour my whole family. A true knight leads by example, not by decree.",bonds:"I swore a sacred oath before the Silver Altar to defend the weak and punish the cruel, and I will uphold it to my dying breath.",flaws:"I secretly believe that no one can match my devotion, and I judge those who fall short of my standards far too harshly.",featuresTraits:["Divine Sense","Lay on Hands","Fighting Style: Dueling","Spellcasting","Divine Smite","Divine Health","Sacred Oath: Oath of Devotion","Channel Divinity: Sacred Weapon","Channel Divinity: Turn the Unholy"],backstory:"Roland was born the second son of House Aldenmere, a noble family whose fortune had dwindled to little more than a crumbling keep and a proud name. Rather than scheme for inheritance, he pledged himself to the Order of the Silver Dawn, a knightly brotherhood devoted to rooting out fiends and undead. He took his oath at the age of seventeen, kneeling on cold stone for three days and nights until dawn light bathed the altar. Now he rides forth in battered but polished armour, convinced that courage and righteousness can reignite the honour his family has lost.",age:"26",height:`6'1"`,weight:"195 lbs",eyes:"Blue",hair:"Sandy blond",skin:"Fair",allies:"The Order of the Silver Dawn — a knightly brotherhood",treasure:"A silver dawn-crest brooch, heirloom of House Aldenmere",spellcastingClass:"paladin",spellcastingAbility:"cha",cantrips:[],spellsKnown:[],spellsPrepared:["Bless","Cure Wounds","Shield of Faith"],hitDie:10,maxHp:28,currentHp:28,tempHp:0,speed:30,sessionNotes:"",classes:[]},k={id:"blog-sorcerer-halfelf-cassara-starbloom",variant:"dnd5e",name:"Cassara Starbloom",playerName:"",race:"half-elf",subrace:"",className:"sorcerer",subclass:"draconic-bloodline",level:3,background:"noble",alignment:"cg",experiencePoints:900,abilityScores:{str:8,dex:14,con:14,int:10,wis:10,cha:15},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:0,con:1,int:0,wis:1,cha:2},skillProficiencies:["persuasion","deception","history","arcana","insight","investigation"],skillExpertise:[],savingThrowProficiencies:["con","cha"],languages:["Common","Elvish","Draconic"],proficienciesOther:["dagger","dart","sling","quarterstaff","light crossbow"],weapons:[{name:"Dagger",attackBonus:4,damage:"1d4+2"},{name:"Light Crossbow",attackBonus:4,damage:"1d8+2"}],armor:"",shield:!1,equipment:["Light Crossbow","20 bolts","Component pouch","Explorer's Pack","2 Daggers","Signet ring","Fine clothes"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I carry myself with the effortless poise of old nobility, though I punctuate every formal greeting with an involuntary spark of golden light from my fingertips. I collect rare perfumes and judge people by their scent before their words.",ideals:"Freedom. No one should be caged by birthright or bloodline; power is meant to liberate, not to shackle.",bonds:"My grandmother was the last in our line to openly bear the dragon mark, and I wear her signet ring as a promise to restore our family's fading name.",flaws:"I am terrified that one day my draconic power will surge beyond my control and harm the people I love.",featuresTraits:["Darkvision","Fey Ancestry","Skill Versatility","Spellcasting","Sorcerous Origin: Draconic Bloodline","Dragon Ancestor","Draconic Resilience","Font of Magic"],backstory:"Cassara grew up in a crumbling manor on the edge of Waterdeep, the last scion of the once-prestigious Starbloom line. When golden scales began to surface along her forearms during her sixteenth nameday ball, the secret her family had kept for generations was laid bare: the blood of a gold dragon runs in their veins. Cast out by scandalized peers, Cassara chose to embrace her heritage rather than hide it. She now travels the Sword Coast seeking forgotten draconic lore, funding her journey with the charm and cunning that only a half-elf noble can muster.",age:"27",height:`5'7"`,weight:"125 lbs",eyes:"Amber with vertical pupils",hair:"Raven black with gold streaks",skin:"Olive with faint golden scales along forearms",allies:"House Starbloom — a diminished noble house with a handful of loyal retainers",treasure:"A worn signet ring bearing the Starbloom crest: a dragon coiled around a blooming star",spellcastingClass:"sorcerer",spellcastingAbility:"cha",cantrips:["Fire Bolt","Prestidigitation","Light","Minor Illusion"],spellsKnown:["Shield","Magic Missile","Scorching Ray","Misty Step"],spellsPrepared:[],hitDie:6,maxHp:20,currentHp:20,tempHp:0,speed:30,sessionNotes:"",classes:[]},v={id:"blog-warlock-tiefling-morthos-grimsoul",variant:"dnd5e",name:"Morthos Grimsoul",playerName:"",race:"tiefling",subrace:"",className:"warlock",subclass:"the-fiend",level:3,background:"charlatan",alignment:"ne",experiencePoints:900,abilityScores:{str:8,dex:14,con:14,int:10,wis:10,cha:15},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:0,con:0,int:1,wis:0,cha:2},skillProficiencies:["arcana","intimidation","deception","sleight of hand"],skillExpertise:[],savingThrowProficiencies:["wis","cha"],languages:["Common","Infernal","Abyssal"],proficienciesOther:["light armor","simple weapons"],weapons:[{name:"Quarterstaff",attackBonus:0,damage:"1d6-1"},{name:"Light Crossbow",attackBonus:4,damage:"1d8+2"}],armor:"Leather",shield:!1,equipment:["Light Crossbow","20 bolts","Leather Armor","2 Daggers","Scholar's Pack","Arcane focus","Fine clothes","Disguise kit"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I keep a running tally of every favor owed to me in a small black ledger, and I never forget a debt. My smile is always a fraction too wide, revealing the sharp canines that most tieflings learn to hide.",ideals:"Power. Knowledge and leverage are the only currencies that never devalue, and I intend to be wealthy beyond measure.",bonds:"Somewhere in the Nine Hells my patron holds the contract I signed in blood; I will find a way to reclaim it and free myself on my own terms.",flaws:"I compulsively lie even when the truth would serve me better, a habit that has cost me every genuine friendship I have ever had.",featuresTraits:["Darkvision","Hellish Resistance","Infernal Legacy","Otherworldly Patron: The Fiend","Pact Magic","Dark One's Blessing","Eldritch Invocations","Pact Boon"],backstory:"Morthos never knew his parents; he was raised in the back rooms of a traveling carnival, learning card tricks and confidence scams before he could read. When the carnival master discovered the boy's infernal bloodline and tried to sell him to a devil-binding cult, Morthos escaped into the night and made a desperate bargain with a fiend who whispered from the shadows. The pact granted him eldritch power but bound his soul to a contract he barely understood. Now he drifts from city to city, running elaborate cons to fund his search for a way to outwit his own patron.",age:"24",height:`5'11"`,weight:"170 lbs",eyes:"Solid crimson, no visible pupils",hair:"Black, slicked back",skin:"Dusky purple",allies:"The Veil — a loose network of tiefling outcasts who share information and safe houses",treasure:"A tarnished silver coin that always lands on the same side, a gift from his patron",spellcastingClass:"warlock",spellcastingAbility:"cha",cantrips:["Eldritch Blast","Minor Illusion","Chill Touch"],spellsKnown:["Hex","Burning Hands","Hold Person","Misty Step"],spellsPrepared:[],hitDie:8,maxHp:24,currentHp:24,tempHp:0,speed:30,sessionNotes:"",classes:[]},S={id:"blog-druid-elf-fern-wildbloom",variant:"dnd5e",name:"Fern Wildbloom",playerName:"",race:"elf",subrace:"wood-elf",className:"druid",subclass:"circle-of-the-land",level:3,background:"outlander",alignment:"ng",experiencePoints:900,abilityScores:{str:10,dex:14,con:14,int:10,wis:15,cha:8},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:0,dex:2,con:0,int:0,wis:1,cha:0},skillProficiencies:["nature","perception","athletics","survival"],skillExpertise:[],savingThrowProficiencies:["int","wis"],languages:["Common","Elvish","Druidic","Sylvan"],proficienciesOther:["light armor","medium armor","shields","club","dagger","dart","javelin","mace","quarterstaff","scimitar","sickle","sling","spear","herbalism kit"],weapons:[{name:"Scimitar",attackBonus:5,damage:"1d6+3"},{name:"Quarterstaff",attackBonus:2,damage:"1d6"}],armor:"Leather",shield:!0,equipment:["Leather Armor","Wooden Shield","Scimitar","Explorer's Pack","Druidic focus (mistletoe)","Hunting trap","Staff","Traveler's clothes"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I speak to plants as though they can hear me, and I am convinced they answer in the rustle of their leaves. I always sleep outdoors when I can, finding rooftops and walls suffocating.",ideals:"Balance. Every creature has its place in the great cycle, and it is my duty to ensure that cycle is never broken.",bonds:"The ancient oak at the heart of the Silverwood is the oldest living thing I have ever known; I would cross any distance to protect it.",flaws:"I struggle to understand city customs and often offend people without realizing it, mistaking their politeness for dishonesty.",featuresTraits:["Darkvision","Keen Senses","Fey Ancestry","Trance","Mask of the Wild","Druidic","Spellcasting","Wild Shape","Druid Circle: Circle of the Land","Bonus Cantrip","Natural Recovery"],backstory:"Fern was found as an infant cradled in the roots of a great oak by a circle of wood elf druids who took her arrival as an omen from the forest itself. She grew up learning the old ways: reading weather in the flight of birds, coaxing healing herbs from barren soil, and shifting into the shapes of woodland creatures. When loggers from a distant barony began to push deeper into the Silverwood, Fern volunteered to venture beyond the treeline and seek allies among the civilized races. She carries a sprig of mistletoe from her grove as both a druidic focus and a reminder of the home she fights to preserve.",age:"142",height:`5'6"`,weight:"115 lbs",eyes:"Moss green",hair:"Auburn with woven wildflowers",skin:"Tan with bark-like freckles",allies:"Circle of the Silverwood — a druidic order that tends the ancient forest",treasure:'A polished river stone etched with a druidic glyph meaning "growth"',spellcastingClass:"druid",spellcastingAbility:"wis",cantrips:["Druidcraft","Produce Flame","Shillelagh"],spellsKnown:[],spellsPrepared:["Cure Wounds","Faerie Fire","Thunderwave","Goodberry","Healing Word","Pass without Trace"],hitDie:8,maxHp:24,currentHp:24,tempHp:0,speed:35,sessionNotes:"",classes:[]},B={id:"blog-barbarian-dragonborn-skar-flamerage",variant:"dnd5e",name:"Skar Flamerage",playerName:"",race:"dragonborn",subrace:"",className:"barbarian",subclass:"path-of-the-berserker",level:3,background:"outlander",alignment:"cn",experiencePoints:900,abilityScores:{str:15,dex:13,con:14,int:8,wis:12,cha:10},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:2,dex:0,con:0,int:0,wis:0,cha:1},skillProficiencies:["athletics","intimidation","perception","survival"],skillExpertise:[],savingThrowProficiencies:["str","con"],languages:["Common","Draconic"],proficienciesOther:["light armor","medium armor","shields","simple weapons","martial weapons"],weapons:[{name:"Greataxe",attackBonus:5,damage:"1d12+3"},{name:"Javelin",attackBonus:5,damage:"1d6+3"}],armor:"",shield:!1,equipment:["Greataxe","4 Javelins","Explorer's Pack","Traveler's clothes","Staff","Hunting trap"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I measure the worth of others by their willingness to stand and fight rather than talk. When I laugh, the ground seems to tremble, and I laugh often because the world is either funny or about to be broken.",ideals:"Strength. The strong survive and the weak are sheltered by those strong enough to protect them; that is the only law that matters.",bonds:"My clan was scattered by a white dragon that froze our mountain home; I carry a shard of its ice-scarred claw as a vow to one day return and reclaim our territory.",flaws:"My rage is a living thing that sometimes escapes its leash. I have destroyed friendships, furniture, and at least one tavern because I could not calm the fire inside.",featuresTraits:["Draconic Ancestry","Breath Weapon","Damage Resistance","Rage","Unarmored Defense","Reckless Attack","Danger Sense","Primal Path: Path of the Berserker","Frenzy"],backstory:"Skar was born during a volcanic eruption in the Dragontooth Mountains, an event his clan interpreted as a blessing from Bahamut. He grew up wrestling dire wolves and splitting boulders for sport, earning his place as the war chief's champion before his fifteenth winter. When a white dragon descended upon the clan and scattered them across the frozen peaks, Skar was the last to retreat, carrying two wounded elders on his back through a blizzard. Alone and burning with fury, he now roams the lowlands as a sellsword, channeling his rage into every swing of his greataxe while searching for survivors of his broken clan.",age:"19",height:`6'5"`,weight:"280 lbs",eyes:"Molten orange",hair:"None",skin:"Crimson scales with charcoal ridges",allies:"Clan Flamerage — scattered dragonborn survivors of the mountain fall",treasure:"A shard of white dragon claw worn on a leather cord around his neck",spellcastingClass:"",spellcastingAbility:"",cantrips:[],spellsKnown:[],spellsPrepared:[],hitDie:12,maxHp:32,currentHp:32,tempHp:0,speed:30,sessionNotes:"",classes:[]},x={id:"blog-bard-human-marco-fortunato",variant:"dnd5e",name:"Marco Fortunato",playerName:"",race:"human",subrace:"",className:"bard",subclass:"college-of-lore",level:3,background:"entertainer",alignment:"cg",experiencePoints:900,abilityScores:{str:8,dex:14,con:14,int:10,wis:10,cha:15},backgroundBonuses:{},asiBonuses:{},speciesBonuses:{str:1,dex:1,con:1,int:1,wis:1,cha:1},skillProficiencies:["persuasion","deception","history","acrobatics","performance","intimidation","insight","arcana"],skillExpertise:[],savingThrowProficiencies:["dex","cha"],languages:["Common","Elvish","Dwarvish"],proficienciesOther:["light armor","simple weapons","hand crossbow","longsword","rapier","shortsword","lute","flute","drum"],weapons:[{name:"Rapier",attackBonus:4,damage:"1d8+2"},{name:"Dagger",attackBonus:4,damage:"1d4+2"}],armor:"Leather",shield:!1,equipment:["Rapier","Diplomat's Pack","Lute","Leather Armor","Dagger","Musical instruments","Letter of recommendation","Costume clothes"],coins:{cp:0,sp:0,ep:0,gp:10,pp:0},personalityTraits:"I always have a song ready for any occasion, and I firmly believe there is no problem that cannot be solved by the right melody. I collect stories the way other people collect coins, trading them freely and never letting a good tale go untold.",ideals:"Beauty. Art and music elevate the soul; when I perform, I give people a reason to hope even in the darkest times.",bonds:"My old theater troupe, the Fortunato Players, was disbanded by a jealous noble who accused us of sedition. I will clear our name and see us perform together once more.",flaws:"I cannot resist showing off, even when subtlety would be the wiser course. My need for applause has landed me in more trouble than any monster ever has.",featuresTraits:["Spellcasting","Bardic Inspiration","Jack of All Trades","Song of Rest","Bard College: College of Lore","Expertise","Bonus Proficiencies","Cutting Words"],backstory:"Marco was born to a family of traveling performers in a bustling trade city, learning to sing before he could walk and to fence before he could write his own name. His troupe, the Fortunato Players, was renowned for satirical plays that mocked the powerful and uplifted the downtrodden. When a vindictive duke shut them down and scattered the troupe, Marco took to the road with nothing but his lute and his wits. He now wanders from tavern to court, gathering allies and secrets in equal measure, always searching for the leverage he needs to restore his family's legacy.",age:"26",height:`5'9"`,weight:"155 lbs",eyes:"Warm brown",hair:"Curly chestnut",skin:"Olive",allies:"The Fortunato Players — a disbanded but loyal theater troupe",treasure:"A worn playbill from the troupe's final performance, kept folded inside his lute case",spellcastingClass:"bard",spellcastingAbility:"cha",cantrips:["Vicious Mockery","Minor Illusion"],spellsKnown:["Healing Word","Faerie Fire","Thunderwave","Charm Person","Hold Person","Invisibility"],spellsPrepared:[],hitDie:8,maxHp:24,currentHp:24,tempHp:0,speed:30,sessionNotes:"",classes:[]},D=[{slug:"ranger-elf-elara-nightwhisper",variant:"dnd5e",characterData:s,tags:["ranger","elf","dnd5e"]},{slug:"barbarian-orc-grokk-ironfang",variant:"dnd5e",characterData:n,tags:["barbarian","orc","dnd5e"]},{slug:"bard-human-lyra-silvertongue",variant:"dnd5e",characterData:t,tags:["bard","human","dnd5e"]},{slug:"fighter-dwarf-thordin-stoneheart",variant:"dnd5e",characterData:r,tags:["fighter","dwarf","dnd5e"]},{slug:"druid-human-rowan-ashwood",variant:"dnd5e",characterData:i,tags:["druid","human","dnd5e"]},{slug:"barbarian-dwarf-bera-battlehammer",variant:"dnd5e",characterData:o,tags:["barbarian","dwarf","dnd5e"]},{slug:"monk-human-kael-windwalker",variant:"dnd5e",characterData:l,tags:["monk","human","dnd5e"]},{slug:"sorcerer-dragonborn-varek-brightscale",variant:"dnd5e",characterData:h,tags:["sorcerer","dragonborn","dnd5e"]},{slug:"rogue-halfling-pip-shadowfoot",variant:"dnd5e",characterData:d,tags:["rogue","halfling","dnd5e"]},{slug:"warlock-tiefling-zara-hellfire",variant:"dnd5e",characterData:c,tags:["warlock","tiefling","dnd5e"]},{slug:"warlock-elf-vex-nightpact",variant:"dnd5e",characterData:g,tags:["warlock","elf","dnd5e"]},{slug:"wizard-human-aldric-spellweaver",variant:"dnd5e",characterData:p,tags:["wizard","human","dnd5e"]},{slug:"artificer-gnome-fizzle-gearspark",variant:"dnd5e",characterData:u,tags:["artificer","gnome","dnd5e"]},{slug:"paladin-halfling-bram-thickfoot",variant:"dnd5e",characterData:m,tags:["paladin","halfling","dnd5e"]},{slug:"ranger-gnome-thistle-mossheart",variant:"dnd5e",characterData:f,tags:["ranger","gnome","dnd5e"]},{slug:"cleric-elf-arael-dawnwhisper",variant:"dnd5e",characterData:w,tags:["cleric","elf","dnd5e"]},{slug:"rogue-tiefling-nyx-shadowcloak",variant:"dnd5e",characterData:b,tags:["rogue","tiefling","dnd5e"]},{slug:"fighter-human-ser-roland-the-bold",variant:"dnd5e",characterData:y,tags:["fighter","human","dnd5e"]},{slug:"druid-elf-cassara-starbloom",variant:"dnd5e",characterData:k,tags:["druid","elf","dnd5e"]},{slug:"warlock-tiefling-morthos-grimsoul",variant:"dnd5e",characterData:v,tags:["warlock","tiefling","dnd5e"]},{slug:"druid-human-fern-wildbloom",variant:"dnd5e",characterData:S,tags:["druid","human","dnd5e"]},{slug:"barbarian-orc-skar-flamerage",variant:"dnd5e",characterData:B,tags:["barbarian","orc","dnd5e"]},{slug:"fighter-human-marco-fortunato",variant:"dnd5e",characterData:x,tags:["fighter","human","dnd5e"]}];function I(e){return D.find(a=>a.slug===e)}export{D as b,I as g};
